// ---- Interface ----
type UserRepository interface {
    GetUser(id int) (string, error)
    SaveUser(name string) error
}

// ---- Real implementation ----
type DatabaseRepo struct{}

func (db DatabaseRepo) GetUser(id int) (string, error) {
    // Real database call
    return "", nil
}

func (db DatabaseRepo) SaveUser(name string) error {
    // Real database call
    return nil
}

// ---- Service that uses the interface ----
type UserService struct {
    repo UserRepository
}

func NewUserService(repo UserRepository) *UserService {
    return &UserService{repo: repo}
}

func (s *UserService) GetUserName(id int) (string, error) {
    return s.repo.GetUser(id)
}

func (s *UserService) CreateUser(name string) error {
    if name == "" {
        return fmt.Errorf("name cannot be empty")
    }
    return s.repo.SaveUser(name)
}

// ---- Mock implementation for testing ----
type MockRepo struct {
    GetUserFunc  func(id int) (string, error)
    SaveUserFunc func(name string) error
}

func (m MockRepo) GetUser(id int) (string, error) {
    if m.GetUserFunc != nil {
        return m.GetUserFunc(id)
    }
    return "", nil
}

func (m MockRepo) SaveUser(name string) error {
    if m.SaveUserFunc != nil {
        return m.SaveUserFunc(name)
    }
    return nil
}

// ---- Tests ----
func TestGetUserName(t *testing.T) {
    mock := MockRepo{
        GetUserFunc: func(id int) (string, error) {
            if id == 1 {
                return "Alice", nil
            }
            return "", fmt.Errorf("user not found")
        },
    }

    service := NewUserService(mock)

    // Test existing user
    name, err := service.GetUserName(1)
    if err != nil {
        t.Errorf("Expected no error, got %v", err)
    }
    if name != "Alice" {
        t.Errorf("Expected 'Alice', got '%s'", name)
    }

    // Test non-existing user
    _, err = service.GetUserName(2)
    if err == nil {
        t.Error("Expected error, got nil")
    }
}

func TestCreateUser(t *testing.T) {
    savedName := ""
    mock := MockRepo{
        SaveUserFunc: func(name string) error {
            savedName = name
            return nil
        },
    }

    service := NewUserService(mock)

    // Test valid user
    err := service.CreateUser("Bob")
    if err != nil {
        t.Errorf("Expected no error, got %v", err)
    }
    if savedName != "Bob" {
        t.Errorf("Expected saved name 'Bob', got '%s'", savedName)
    }

    // Test empty name
    err = service.CreateUser("")
    if err == nil {
        t.Error("Expected error for empty name, got nil")
    }
}

