phase3.solution:
package main

import (
    "fmt"
    "testing"
)

type Logger interface {
    Log(message string) error
}

type UserService struct {
    logger Logger
}

func NewUserService(logger Logger) *UserService {
    return &UserService{logger: logger}
}

func (s *UserService) CreateUser(name string) error {
    if name == "" {
        return fmt.Errorf("name cannot be empty")
    }
    return s.logger.Log("User created: " + name)
}

type MockLogger struct {
    LastMessage string
    LastError   error
}

func (m *MockLogger) Log(message string) error {
    m.LastMessage = message
    return m.LastError
}

func TestCreateUser(t *testing.T) {
    // Test valid name
    mock := &MockLogger{}
    service := NewUserService(mock)

    err := service.CreateUser("Alice")
    if err != nil {
        t.Errorf("Expected no error, got %v", err)
    }
    expected := "User created: Alice"
    if mock.LastMessage != expected {
        t.Errorf("Expected %q, got %q", expected, mock.LastMessage)
    }

    // Test empty name
    err = service.CreateUser("")
    if err == nil {
        t.Error("Expected error for empty name, got nil")
    }
    // Message should not be set for empty name
    if mock.LastMessage != expected {
        t.Errorf("Expected no log for empty name")
    }
}
